consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
.wrapper {
  width: 100%;
  height: var(--dimension-size-400);
  display: flex;
  align-items: center;
  background-color: var(--color-background-primary);
  border-radius: var(--dimension-radius-075);
  box-shadow: var(--effect-elevation-depressed-sm);
  box-sizing: border-box;
}

.wrapper:focus-within {
  box-shadow: inset 0 0 0 1.25px var(--color-foreground-bold-brand);
}

.row {
  display: flex;
  align-items: center;
  width: 100%;
  height: 100%;
  gap: var(--dimension-space-050);
}

.input {
  flex: 1;
  min-width: 0;
  height: 100%;
  padding: 0 var(--dimension-space-100);
  background: transparent;
  border: none;
  outline: none;
  font-family: inherit;
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
  color: var(--color-foreground-primary);
  border-radius: var(--dimension-radius-075);
  -webkit-appearance: none;
  appearance: none;
}

.input:disabled { opacity: 0.5; cursor: not-allowed; }
.input::placeholder { color: var(--color-foreground-secondary); }
.input:focus::placeholder { color: var(--color-foreground-tertiary); }

/* Hide native search clear */
.input[type="search"]::-webkit-search-cancel-button,
.input[type="search"]::-webkit-search-decoration { display: none; }

.clearButton {
  flex-shrink: 0;
  margin-right: var(--dimension-space-050);
  padding: var(--dimension-space-050);
  border: none;
  background: none;
  cursor: pointer;
  color: var(--color-foreground-secondary);
  border-radius: var(--dimension-radius-050);
  display: flex;
  align-items: center;
  justify-content: center;
}

.clearButton:hover { background-color: var(--color-interaction-hover); }

.suffix {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
  flex-shrink: 0;
  margin-right: var(--dimension-space-050);
}

import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import type { IconComponent } from '@/types/icons';
import styles from './Input.module.css';

export type InputType = 'text' | 'email' | 'tel' | 'url' | 'search' | 'password';

export interface InputProps {
  value: string;
  onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  id?: string;
  placeholder?: string;
  autoFocus?: boolean;
  className?: string;
  type?: InputType;
  inactive?: boolean;
  onKeyDown?: React.KeyboardEventHandler<HTMLInputElement>;
  /** Content rendered inside the field on the right. */
  suffix?: React.ReactNode;
  /** Icon for clear button (search type). */
  clearIcon?: IconComponent;
  'aria-label'?: string;
}

export const Input = forwardRef<HTMLDivElement, InputProps>(
  (
    {
      value,
      onChange,
      id,
      placeholder,
      autoFocus = false,
      className,
      type = 'text',
      inactive = false,
      onKeyDown,
      suffix,
      clearIcon: ClearIcon,
      'aria-label': ariaLabel,
    },
    ref
  ) => {
    const showClear = type === 'search' && value.length > 0 && !inactive;

    const handleClear = () => {
      onChange({ target: { value: '' } } as React.ChangeEvent<HTMLInputElement>);
    };

    return (
      <div ref={ref} className={cn(styles.wrapper, className)}>
        <div className={styles.row}>
          <input
            type={type}
            id={id}
            value={value}
            onChange={onChange}
            onKeyDown={onKeyDown}
            placeholder={placeholder}
            className={styles.input}
            autoFocus={autoFocus}
            disabled={inactive}
            aria-label={ariaLabel}
          />
          {showClear && (
            <button type="button" className={styles.clearButton} onClick={handleClear} aria-label="Clear">
              {ClearIcon ? <ClearIcon size={16} /> : <span aria-hidden>&times;</span>}
            </button>
          )}
          {suffix && <div className={styles.suffix}>{suffix}</div>}
        </div>
      </div>
    );
  }
);

Input.displayName = 'Input';
